-- ----------------------------
-- Table structure for sys_approval
-- ----------------------------
DROP TABLE IF EXISTS `sys_approval`;
CREATE TABLE `sys_approval`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT,
  `user_id` bigint(0) NULL DEFAULT NULL COMMENT '员工id',
  `is_authorize` tinyint(1) UNSIGNED ZEROFILL NOT NULL,
  `dept_id` bigint(0) NULL DEFAULT NULL COMMENT '该员工部门id',
  `type_num` int(0) NOT NULL DEFAULT 4 COMMENT '事务类型id，1职务升降、2人员变动、3出差报销、4其他',
  `remark1` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '事务内容',
  `apply_time` datetime(0) NULL DEFAULT NULL COMMENT '事务申请时间',
  `status` tinyint(0) UNSIGNED NULL DEFAULT 0 COMMENT '0未审核，1审核通过，2驳回，3撤销',
  `approval_user_id` bigint(0) NULL DEFAULT NULL COMMENT '审批用户id',
  `approval_time` datetime(0) NULL DEFAULT NULL COMMENT '审批时间',
  `remark2` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '上级回复详细内容',
  `is_deleted` tinyint(0) UNSIGNED NULL DEFAULT 0,
  `create_user` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `create_time` date NULL DEFAULT NULL,
  `update_user` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NULL DEFAULT NULL,
  `update_time` date NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 662501312881037320 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '事务申请表' ROW_FORMAT = Dynamic;

