  `active_timeout` bigint(0) NULL DEFAULT -1 COMMENT 'Token最低活跃频率（单位：秒，-1：不限制，永不冻结）',
  `timeout` bigint(0) NULL DEFAULT 2592000 COMMENT 'Token有效期（单位：秒，-1：永不过期）',
