-- ----------------------------
-- Table structure for sys_message_user
-- ----------------------------
DROP TABLE IF EXISTS `sys_message_user`;
CREATE TABLE `sys_message_user`  (
  `message_id` bigint(0) NOT NULL COMMENT '消息ID',
  `user_id` bigint(0) NOT NULL COMMENT '用户ID',
  `is_read` bit(1) NOT NULL DEFAULT b'0' COMMENT '是否已读',
  `read_time` datetime(0) NULL DEFAULT NULL COMMENT '读取时间',
  PRIMARY KEY (`message_id`, `user_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '消息和用户关联表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_message_user
-- ----------------------------

-- ----------------------------
-- Table structure for sys_notice
-- ----------------------------
DROP TABLE IF EXISTS `sys_notice`;
CREATE TABLE `sys_notice`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT 'ID',
  `title` varchar(150) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '标题',
  `content` mediumtext CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '内容',
  `type` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '类型',
  `effective_time` datetime(0) NULL DEFAULT NULL COMMENT '生效时间',
  `terminate_time` datetime(0) NULL DEFAULT NULL COMMENT '终止时间',
  `notice_scope` int(0) NOT NULL COMMENT '通知范围',
  `notice_users` json NULL COMMENT '通知用户',
  `sort` int(0) NOT NULL DEFAULT 999 COMMENT '排序',
  `create_user` bigint(0) NOT NULL COMMENT '创建人',
  `create_time` datetime(0) NOT NULL COMMENT '创建时间',
  `update_user` bigint(0) NULL DEFAULT NULL COMMENT '修改人',
  `update_time` datetime(0) NULL DEFAULT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_create_user`(`create_user`) USING BTREE,
  INDEX `idx_update_user`(`update_user`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 656165409652764702 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_0900_ai_ci COMMENT = '公告表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_notice
